//  sg2_fused_elem_F_mxfp4_sm80_M_d16_kernel  [F/mxfp4/sm80/M/d16]
// ===========================================================

template <typename scalar_t, int D_INNER = 16>
__launch_bounds__(256, 2)
__global__ void sg2_fused_elem_F_mxfp4_sm80_M_d16_kernel(
    scalar_t* __restrict__ param,
    const scalar_t* __restrict__ grad,
    const scalar_t* __restrict__ sharpness,
    float* __restrict__ exp_avg,
    float* __restrict__ exp_avg_sq,
    float* __restrict__ mu,
    float* __restrict__ gru_state,
    const float* __restrict__ fwd_scan_out,
    const float* __restrict__ bwd_scan_out,
    const float* __restrict__ out_proj_fwd_W,
    const float* __restrict__ out_proj_bwd_W,
    const float* __restrict__ gru_Wz, const float* __restrict__ gru_bz,
    const float* __restrict__ gru_Wr, const float* __restrict__ gru_br,
    const float* __restrict__ gru_Wh, const float* __restrict__ gru_bh,
    const float* __restrict__ peer_query_Ws,
    const float* __restrict__ prod_keys_A,
    const float* __restrict__ prod_keys_B,
    const uint8_t* __restrict__ expert_W1_q,
    const uint8_t* __restrict__ expert_W1_exp,
    const uint8_t* __restrict__ expert_W2_q,
    const uint8_t* __restrict__ expert_W2_exp,
    const uint8_t* __restrict__ expert_b1_q,
    const uint8_t* __restrict__ expert_b1_exp,
    const uint8_t* __restrict__ expert_b2_q,
    const uint8_t* __restrict__ expert_b2_exp,
    const float mxfp4_scale,
    const float rescale, const float alpha, const float lamb_eff,
    const float beta1, const float beta2, const float lr,
    const float wd_eff, const float eps, const float bc1, const float bc2,
    const bool* __restrict__ active_mask,
    int* __restrict__ expert_counts,
    const int N, const int d_model,
    const int gru_hidden, const int num_heads, const int pk_dim,
    const int expert_hidden, const int num_experts
) {
    const int gru_input_dim = 2 + 2 * d_model;
    const int gru_row_len = gru_input_dim + gru_hidden;
    const int op_size = d_model * D_INNER;
    const int gru_mat_size = gru_hidden * gru_row_len;

    extern __shared__ float smem[];

    float* s_out_fwd = smem;
    float* s_out_bwd = smem + op_size;
    float* s_gru_Wz  = s_out_bwd + op_size;
    float* s_gru_Wr  = s_gru_Wz + gru_mat_size;
    float* s_gru_Wh  = s_gru_Wr + gru_mat_size;
    float* s_gru_bz  = s_gru_Wh + gru_mat_size;
    float* s_gru_br  = s_gru_bz + gru_hidden;
    float* s_gru_bh  = s_gru_br + gru_hidden;
    float* s_expert_W1 = s_gru_bh + gru_hidden;
    float* s_expert_b1 = s_expert_W1 + num_experts * expert_hidden;
    float* s_expert_W2 = s_expert_b1 + num_experts * expert_hidden;
    float* s_expert_b2 = s_expert_W2 + num_experts * expert_hidden;

    const int tid = threadIdx.x;
    const int block_size = blockDim.x;

    // cp.async prefetch out_proj weights
    for (int i = tid; i < 2 * op_size; i += block_size) {
        const float* src = (i < op_size) ? &out_proj_fwd_W[i] : &out_proj_bwd_W[i - op_size];
    #if GROK_CUDA && defined(__CUDA_ARCH__) && __CUDA_ARCH__ >= 800
        __pipeline_memcpy_async(&smem[i], src, sizeof(float));
    #else
        smem[i] = *src;
    #endif
    }
    // cp.async prefetch GRU weights
    const float* gru_gmem[] = {gru_Wz, gru_Wr, gru_Wh, gru_bz, gru_br, gru_bh};
    int gru_sizes[] = {gru_mat_size, gru_mat_size, gru_mat_size, gru_hidden, gru_hidden, gru_hidden};
    float* gru_dst = s_gru_Wz;
    int gru_offset = 0;
    for (int seg = 0; seg < 6; seg++) {
        for (int i = tid; i < gru_sizes[seg]; i += block_size) {
    #if GROK_CUDA && defined(__CUDA_ARCH__) && __CUDA_ARCH__ >= 800
            __pipeline_memcpy_async(&gru_dst[gru_offset + i], &gru_gmem[seg][i], sizeof(float));
    #else
            gru_dst[gru_offset + i] = gru_gmem[seg][i];
    #endif
        }
        gru_offset += gru_sizes[seg];
    }
    #if GROK_CUDA && defined(__CUDA_ARCH__) && __CUDA_ARCH__ >= 800
    __pipeline_commit();
    #endif

    // MXFP4 dequantize: extract nibble, lookup exponent, multiply scale
    const int exp_total = num_experts * expert_hidden;
    for (int i = tid; i < (exp_total + 1) / 2; i += block_size) {
        uint8_t pw1 = expert_W1_q[i];
        uint8_t pb1 = expert_b1_q[i];
        uint8_t pw2 = expert_W2_q[i];
        uint8_t ew1 = expert_W1_exp[2*i / 32];
        uint8_t eb1 = expert_b1_exp[2*i / 32];
        uint8_t ew2 = expert_W2_exp[2*i / 32];
        s_expert_W1[2*i]   = dequant_mxfp4_gen(pw1 & 0x0F, ew1, mxfp4_scale);
        if (2*i+1 < exp_total) s_expert_W1[2*i+1] = dequant_mxfp4_gen((pw1>>4)&0x0F, ew1, mxfp4_scale);
        s_expert_b1[2*i]   = dequant_mxfp4_gen(pb1 & 0x0F, eb1, mxfp4_scale);
        if (2*i+1 < exp_total) s_expert_b1[2*i+1] = dequant_mxfp4_gen((pb1>>4)&0x0F, eb1, mxfp4_scale);
        s_expert_W2[2*i]   = dequant_mxfp4_gen(pw2 & 0x0F, ew2, mxfp4_scale);
        if (2*i+1 < exp_total) s_expert_W2[2*i+1] = dequant_mxfp4_gen((pw2>>4)&0x0F, ew2, mxfp4_scale);
    }
    for (int i = tid; i < (num_experts + 1) / 2; i += block_size) {
        uint8_t p = expert_b2_q[i];
        uint8_t e = expert_b2_exp[2*i / 32];
        s_expert_b2[2*i]   = dequant_mxfp4_gen(p & 0x0F, e, mxfp4_scale);
        if (2*i+1 < num_experts) s_expert_b2[2*i+1] = dequant_mxfp4_gen((p>>4)&0x0F, e, mxfp4_scale);
    }
    #if GROK_CUDA && defined(__CUDA_ARCH__) && __CUDA_ARCH__ >= 800
    __pipeline_commit();
    __pipeline_wait_prior(0);
    #endif
    __syncthreads();

    // Per-element processing
    const int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx >= N) return;

    // MoE early-exit
    if (!active_mask[idx]) return;

    float g = static_cast<float>(grad[idx]);
    float s = static_cast<float>(sharpness[idx]);
    if (!isfinite(g)) g = 0.0f;
    if (!isfinite(s)) s = 0.0f;
    const int half_d = d_model / 2;
    const int peer_input_dim = gru_hidden + 2 * d_model + 2;

    // ── Step 1: Mamba out_proj ──
    float fwd_scan[MAX_D_INNER], bwd_scan[MAX_D_INNER];
    #pragma unroll
    for (int j = 0; j < D_INNER; j += 4) {
        float4 fwd4 = *reinterpret_cast<const float4*>(&fwd_scan_out[idx * D_INNER + j]);
        float4 bwd4 = *reinterpret_cast<const float4*>(&bwd_scan_out[idx * D_INNER + j]);
        fwd_scan[j]   = fwd4.x; fwd_scan[j+1] = fwd4.y;
        fwd_scan[j+2] = fwd4.z; fwd_scan[j+3] = fwd4.w;
        bwd_scan[j]   = bwd4.x; bwd_scan[j+1] = bwd4.y;
        bwd_scan[j+2] = bwd4.z; bwd_scan[j+3] = bwd4.w;
    }

    float fwd_ctx[MAX_D_MODEL], bwd_ctx[MAX_D_MODEL];
    for (int d = 0; d < d_model; d++) {
        float fwd_val = 0.0f, bwd_val = 0.0f;
        #pragma unroll
        for (int j = 0; j < D_INNER; j++) {
            fwd_val += s_out_fwd[d * D_INNER + j] * fwd_scan[j];
            bwd_val += s_out_bwd[d * D_INNER + j] * bwd_scan[j];
        }
        fwd_ctx[d] = fwd_val;
        bwd_ctx[d] = bwd_val;
    }

    // ── Step 2: GRU update ──
    float h_old[MAX_GRU_HIDDEN];
    for (int j = 0; j < gru_hidden; j++)
        h_old[j] = stream_load(&gru_state[idx * gru_hidden + j]);

    float z_gate[MAX_GRU_HIDDEN], r_gate[MAX_GRU_HIDDEN];
    for (int j = 0; j < gru_hidden; j++) {
        float val_z = s_gru_bz[j];
        float val_r = s_gru_br[j];
        val_z += s_gru_Wz[j * gru_row_len + 0] * g;
        val_z += s_gru_Wz[j * gru_row_len + 1] * s;
        val_r += s_gru_Wr[j * gru_row_len + 0] * g;
        val_r += s_gru_Wr[j * gru_row_len + 1] * s;
        int off = 2;
        for (int d = 0; d < d_model; d++) {
            val_z += s_gru_Wz[j * gru_row_len + off + d] * fwd_ctx[d];
            val_r += s_gru_Wr[j * gru_row_len + off + d] * fwd_ctx[d];
        }
        off += d_model;
        for (int d = 0; d < d_model; d++) {
            val_z += s_gru_Wz[j * gru_row_len + off + d] * bwd_ctx[d];
            val_r += s_gru_Wr[j * gru_row_len + off + d] * bwd_ctx[d];
        }
        off += d_model;
        for (int k = 0; k < gru_hidden; k++) {
            val_z += s_gru_Wz[j * gru_row_len + off + k] * h_old[k];
            val_r += s_gru_Wr[j * gru_row_len + off + k] * h_old[k];
        }
        z_gate[j] = 1.0f / (1.0f + expf(-val_z));
        r_gate[j] = 1.0f / (1.0f + expf(-val_r));
    }

    float h_new[MAX_GRU_HIDDEN];
    for (int j = 0; j < gru_hidden; j++) {
        float val = s_gru_bh[j];
        val += s_gru_Wh[j * gru_row_len + 0] * g;
        val += s_gru_Wh[j * gru_row_len + 1] * s;
        int off = 2;
        for (int d = 0; d < d_model; d++)
            val += s_gru_Wh[j * gru_row_len + off + d] * fwd_ctx[d];
        off += d_model;
        for (int d = 0; d < d_model; d++)
            val += s_gru_Wh[j * gru_row_len + off + d] * bwd_ctx[d];
        off += d_model;
        for (int k = 0; k < gru_hidden; k++)
            val += s_gru_Wh[j * gru_row_len + off + k] * (r_gate[k] * h_old[k]);
        float h_tilde = tanhf(val);
        h_new[j] = (1.0f - z_gate[j]) * h_old[j] + z_gate[j] * h_tilde;
    }

    for (int j = 0; j < gru_hidden; j++)
        stream_store(&gru_state[idx * gru_hidden + j], h_new[j]);

    // ── Step 3: Multi-head PEER routing + expert MLP ──
    float total_out = 0.0f;
    for (int head = 0; head < num_heads; head++) {
        const float* pq_W = peer_query_Ws + head * d_model * peer_input_dim;
        float query[MAX_D_MODEL];
        for (int d = 0; d < d_model; d++) {
            float val = 0.0f;
            int poff = 0;
            for (int k = 0; k < gru_hidden; k++)
                val += pq_W[d * peer_input_dim + poff + k] * h_new[k];
            poff += gru_hidden;
            for (int k = 0; k < d_model; k++)
                val += pq_W[d * peer_input_dim + poff + k] * fwd_ctx[k];
            poff += d_model;
            for (int k = 0; k < d_model; k++)
                val += pq_W[d * peer_input_dim + poff + k] * bwd_ctx[k];
            poff += d_model;
            val += pq_W[d * peer_input_dim + poff] * g;
            val += pq_W[d * peer_input_dim + poff + 1] * s;
            query[d] = val;
        }

        // Product-key argmax
        const float* keys_A = prod_keys_A + head * pk_dim * half_d;
        const float* keys_B = prod_keys_B + head * pk_dim * half_d;
        int best_a = 0; float best_sa = -1e30f;
        for (int k = 0; k < pk_dim; k++) {
            float dot = 0.0f;
            for (int d = 0; d < half_d; d++)
                dot += query[d] * LDG(&keys_A[k * half_d + d]);
            if (dot > best_sa) { best_sa = dot; best_a = k; }
        }
        int best_b = 0; float best_sb = -1e30f;
        for (int k = 0; k < pk_dim; k++) {
            float dot = 0.0f;
            for (int d = 0; d < half_d; d++)
                dot += query[half_d + d] * LDG(&keys_B[k * half_d + d]);
            if (dot > best_sb) { best_sb = dot; best_b = k; }
        }
        int expert_idx = best_a * pk_dim + best_b;
        if (expert_idx >= num_experts) expert_idx = num_experts - 1;
        if (expert_counts != nullptr)
            atomicAdd(&expert_counts[expert_idx], 1);

        // Expert MLP: ReLU hidden layer
        float head_out = s_expert_b2[expert_idx];
        for (int h = 0; h < expert_hidden; h++) {
            float z_val = s_expert_W1[expert_idx * expert_hidden + h] * g
                        + s_expert_b1[expert_idx * expert_hidden + h];
            z_val = fmaxf(z_val, 0.0f);
            head_out += s_expert_W2[expert_idx * expert_hidden + h] * z_val;
        }
        total_out += head_out;
    }

    // ── Step 4: Smart gradient ──
    float smart_grad = g + rescale * total_out / static_cast<float>(num_heads);

    // ── Step 5: Mu EMA update ──
    float mu_val = stream_load(&mu[idx]);
    mu_val = alpha * mu_val + (1.0f - alpha) * g;
    stream_store(&mu[idx], mu_val);

    // ── Step 6: Adam update ──
    float fg = smart_grad + lamb_eff * mu_val;
    float ea = stream_load(&exp_avg[idx]);
    float easq = stream_load(&exp_avg_sq[idx]);
    ea = beta1 * ea + (1.0f - beta1) * fg;
    easq = beta2 * easq + (1.0f - beta2) * fg * fg;
    stream_store(&exp_avg[idx], ea);
    stream_store(&exp_avg_sq[idx], easq);

    float step_size = lr / bc1;
    float denom = sqrtf(easq / bc2) + eps;
    float p_val = static_cast<float>(param[idx]);
    p_val = p_val * (1.0f - lr * wd_eff) - step_size * ea / denom;
    param[idx] = static_cast<scalar_t>(p_val);
}

void launch_sg2_fused_elem_F_mxfp4_sm80_M_d16(
    torch::Tensor param,
    torch::Tensor grad,
    torch::Tensor sharpness,
    torch::Tensor exp_avg,
    torch::Tensor exp_avg_sq,
    torch::Tensor mu,
    torch::Tensor gru_state,
    torch::Tensor fwd_scan_out,
    torch::Tensor bwd_scan_out,
    float rescale, float alpha, float lamb_eff,
    float beta1, float beta2, float lr,
    float wd_eff, float eps, float bc1, float bc2,
    torch::Tensor active_mask,
    int d_model, int d_inner,
    int gru_hidden, int num_heads, int pk_dim,
    int expert_hidden, int num_experts
) {
    const int N = grad.numel();
    if (N == 0) return;
    const int grid = (N + 256 - 1) / 256;
    const int op_size = d_model * 16;
    const int gru_input_dim = 2 + 2 * d_model;
    const int gru_row_len = gru_input_dim + gru_hidden;
    const int gru_mat_size = gru_hidden * gru_row_len;
    const size_t smem_bytes = (2*op_size + 3*gru_mat_size + 3*gru_hidden
        + 3*num_experts*expert_hidden + num_experts) * sizeof(float);
    // Launch kernel (dispatch omitted — caller instantiates template)
    (void)grid; (void)smem_bytes;
}

// ===========================================================
//  sg2_fused_elem_Q_fp32_generic_D_kernel  [Q/fp32/generic/D]
// ===========================================================

template <typename scalar_t>
__launch_bounds__(256, 2)
__global__ void sg2_fused_elem_Q_fp32_generic_D_kernel(
    scalar_t* __restrict__ param,
    const scalar_t* __restrict__ grad,
    const scalar_t* __restrict__ sharpness,
    int8_t* __restrict__ exp_avg_q,
    float* __restrict__ exp_avg_scales,
    int8_t* __restrict__ exp_avg_sq_q,
    float* __restrict__ exp_avg_sq_scales,
    int8_t* __restrict__ mu_q,
    float* __restrict__ mu_scales,
    __nv_bfloat16* __restrict__ gru_state,
    const float* __restrict__ fwd_scan_out,
    const float* __restrict__ bwd_scan_out,
    const float* __restrict__ out_proj_fwd_W,
    const float* __restrict__ out_proj_bwd_W,
    const float* __restrict__ gru_Wz, const float* __restrict__ gru_bz,
    const float* __restrict__ gru_Wr, const float* __restrict__ gru_br,
    const float* __restrict__ gru_Wh, const float* __restrict__ gru_bh,
    const float* __restrict__ peer_query_Ws,
    const float* __restrict__ prod_keys_A,
    const float* __restrict__ prod_keys_B,
    const float* __restrict__ expert_W1,
    const float* __restrict__ expert_b1,
    const float* __restrict__ expert_W2,
    const float* __restrict__ expert_b2,
    const float rescale, const float alpha, const float lamb_eff,
    const float beta1, const float beta2, const float lr,
    const float wd_eff, const float eps, const float bc1, const float bc2,
    const unsigned global_step,
    int* __restrict__ expert_counts,
    const int N, const int d_model, const int d_inner,
    const int gru_hidden, const int num_heads, const int pk_dim,
    const int expert_hidden, const int num_experts
) {
    const int gru_input_dim = 2 + 2 * d_model;
    const int gru_row_len = gru_input_dim + gru_hidden;
    const int op_size = d_model * d_inner;
    const int gru_mat_size = gru_hidden * gru_row_len;

    extern __shared__ float smem[];

    float* s_out_fwd = smem;
    float* s_out_bwd = smem + op_size;
    float* s_gru_Wz  = s_out_bwd + op_size;
    float* s_gru_Wr  = s_gru_Wz + gru_mat_size;
    float* s_gru_Wh  = s_gru_Wr + gru_mat_size;
    float* s_gru_bz  = s_gru_Wh + gru_mat_size;
    float* s_gru_br  = s_gru_bz + gru_hidden;
    float* s_gru_bh  = s_gru_br + gru_hidden;
    float* s_expert_W1 = s_gru_bh + gru_hidden;
    float* s_expert_b1 = s_expert_W1 + num_experts * expert_hidden;
    float* s_expert_W2 = s_expert_b1 + num_experts * expert_hidden;
    float* s_expert_b2 = s_expert_W2 + num_experts * expert_hidden;

    const int tid = threadIdx.x;
    const int block_size = blockDim.x;

    // Load out_proj weights
    for (int i = tid; i < 2 * op_size; i += block_size) {
        if (i < op_size) smem[i] = out_proj_fwd_W[i];
        else smem[i] = out_proj_bwd_W[i - op_size];
    }
    // Load GRU weights
    const float* gru_gmem[] = {gru_Wz, gru_Wr, gru_Wh, gru_bz, gru_br, gru_bh};
    int gru_sizes[] = {gru_mat_size, gru_mat_size, gru_mat_size, gru_hidden, gru_hidden, gru_hidden};
    float* gru_dst = s_gru_Wz;
    int gru_offset = 0;
    for (int seg = 0; seg < 6; seg++) {
        for (int i = tid; i < gru_sizes[seg]; i += block_size)
            gru_dst[gru_offset + i] = gru_gmem[seg][i];
        gru_offset += gru_sizes[seg];
    }

    for (int i = tid; i < num_experts * expert_hidden; i += block_size) {
        s_expert_W1[i] = expert_W1[i];
        s_expert_b1[i] = expert_b1[i];
        s_expert_W2[i] = expert_W2[i];
    }
    for (int i = tid; i < num_experts; i += block_size) {
        s_expert_b2[i] = expert_b2[i];
    }
    __syncthreads();

    // Per-element processing
    const int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx >= N) return;

    float g = static_cast<float>(grad[idx]);
    float s = static_cast<float>(sharpness[idx]);
    if (!isfinite(g)) g = 0.0f;
    if (!isfinite(s)) s = 0.0f;
    const int half_d = d_model / 2;
    const int peer_input_dim = gru_hidden + 2 * d_model + 2;

    // ── Step 1: Mamba out_proj ──
    float fwd_scan[MAX_D_INNER], bwd_scan[MAX_D_INNER];
    for (int j = 0; j < d_inner; j += 4) {
        float4 fwd4 = *reinterpret_cast<const float4*>(&fwd_scan_out[idx * d_inner + j]);
        float4 bwd4 = *reinterpret_cast<const float4*>(&bwd_scan_out[idx * d_inner + j]);
        fwd_scan[j]   = fwd4.x; fwd_scan[j+1] = fwd4.y;
        fwd_scan[j+2] = fwd4.z; fwd_scan[j+3] = fwd4.w;
        bwd_scan[j]   = bwd4.x; bwd_scan[j+1] = bwd4.y;
        bwd_scan[j+2] = bwd4.z; bwd_scan[j+3] = bwd4.w;
    }

    float fwd_ctx[MAX_D_MODEL], bwd_ctx[MAX_D_MODEL];
    for (int d = 0; d < d_model; d++) {
        float fwd_val = 0.0f, bwd_val = 0.0f;
        for (int j = 0; j < d_inner; j++) {
            fwd_val += s_out_fwd[d * d_inner + j] * fwd_scan[j];
            bwd_val += s_out_bwd[d * d_inner + j] * bwd_scan[j];
        }
        fwd_ctx[d] = fwd_val;
        bwd_ctx[d] = bwd_val;
    }

    // ── Step 2: GRU update ──
    float h_old[MAX_GRU_HIDDEN];
    for (int j = 0; j < gru_hidden; j++)
        h_old[j] = static_cast<float>(gru_state[idx * gru_hidden + j]);

    float z_gate[MAX_GRU_HIDDEN], r_gate[MAX_GRU_HIDDEN];
    for (int j = 0; j < gru_hidden; j++) {
        float val_z = s_gru_bz[j];
        float val_r = s_gru_br[j];
        val_z += s_gru_Wz[j * gru_row_len + 0] * g;
        val_z += s_gru_Wz[j * gru_row_len + 1] * s;
        val_r += s_gru_Wr[j * gru_row_len + 0] * g;
        val_r += s_gru_Wr[j * gru_row_len + 1] * s;
        int off = 2;
        for (int d = 0; d < d_model; d++) {
            val_z += s_gru_Wz[j * gru_row_len + off + d] * fwd_ctx[d];
            val_r += s_gru_Wr[j * gru_row_len + off + d] * fwd_ctx[d];
        }
        off += d_model;
        for (int d = 0; d < d_model; d++) {
            val_z += s_gru_Wz[j * gru_row_len + off + d] * bwd_ctx[d];
            val_r += s_gru_Wr[j * gru_row_len + off + d] * bwd_ctx[d];
        }
        off += d_model;
        for (int k = 0; k < gru_hidden; k++) {
            val_z += s_gru_Wz[j * gru_row_len + off + k] * h_old[k];
            val_r += s_gru_Wr[j * gru_row_len + off + k] * h_old[k];
        }
        z_gate[j] = 1.0f / (1.0f + expf(-val_z));
        r_gate[j] = 1.0f / (1.0f + expf(-val_r));
    }

    float h_new[MAX_GRU_HIDDEN];
    for (int j = 0; j < gru_hidden; j++) {
        float val = s_gru_bh[j];
        val += s_gru_Wh[j * gru_row_len + 0] * g;
        val += s_gru_Wh[j * gru_row_len + 1] * s;
        int off = 2;
        for (int d = 0; d < d_model; d++)
            val += s_gru_Wh[j * gru_row_len + off + d] * fwd_ctx[d];
        off += d_model;
        for (int d = 0; d < d_model; d++)
            val += s_gru_Wh[j * gru_row_len + off + d] * bwd_ctx[d];
        off += d_model;
        for (int k = 0; k < gru_hidden; k++)
            val += s_gru_Wh[j * gru_row_len + off + k] * (r_gate[k] * h_old[k]);
        float h_tilde = tanhf(val);
        h_new[j] = (1.0f - z_gate[j]) * h_old[j] + z_gate[j] * h_tilde;
    }

    unsigned gru_rng = hash_prng(idx * gru_hidden + global_step * 7919u);
    for (int j = 0; j < gru_hidden; j++) {
        gru_state[idx * gru_hidden + j] = float_to_bf16_stochastic(h_new[j], gru_rng);
        gru_rng = hash_prng(gru_rng + j);
    }

    // ── Step 3: Multi-head PEER routing + expert MLP ──
    float total_out = 0.0f;
    for (int head = 0; head < num_heads; head++) {
        const float* pq_W = peer_query_Ws + head * d_model * peer_input_dim;
        float query[MAX_D_MODEL];
        for (int d = 0; d < d_model; d++) {
            float val = 0.0f;
            int poff = 0;
            for (int k = 0; k < gru_hidden; k++)
                val += pq_W[d * peer_input_dim + poff + k] * h_new[k];
            poff += gru_hidden;
            for (int k = 0; k < d_model; k++)
                val += pq_W[d * peer_input_dim + poff + k] * fwd_ctx[k];
            poff += d_model;
            for (int k = 0; k < d_model; k++)
                val += pq_W[d * peer_input_dim + poff + k] * bwd_ctx[k];
            poff += d_model;
            val += pq_W[d * peer_input_dim + poff] * g;
            val += pq_W[d * peer_input_dim + poff + 1] * s;
            query[d] = val;
        }

        // Product-key argmax
        const float* keys_A = prod_keys_A + head * pk_dim * half_d;
        const float* keys_B = prod_keys_B + head * pk_dim * half_d;
        int best_a = 0; float best_sa = -1e30f;
        for (int k = 0; k < pk_dim; k++) {
            float dot = 0.0f;
            for (int d = 0; d < half_d; d++)
                dot += query[d] * LDG(&keys_A[k * half_d + d]);
            if (dot > best_sa) { best_sa = dot; best_a = k; }
        }
        int best_b = 0; float best_sb = -1e30f;
        for (int k = 0; k < pk_dim; k++) {
            float dot = 0.0f;
            for (int d = 0; d < half_d; d++)
                dot += query[half_d + d] * LDG(&keys_B[k * half_d + d]);
            if (dot > best_sb) { best_sb = dot; best_b = k; }
        }
        int expert_idx = best_a * pk_dim + best_b;
        if (expert_idx >= num_experts) expert_idx = num_experts - 1;
        if (expert_counts != nullptr)
            atomicAdd(&expert_counts[expert_idx], 1);

        // Expert MLP: ReLU hidden layer
        float head_out = s_expert_b2[expert_idx];
        for (int h = 0; h < expert_hidden; h++) {
            float z_val = s_expert_W1[expert_idx * expert_hidden + h] * g
                        + s_expert_b1[expert_idx * expert_hidden + h];
            z_val = fmaxf(z_val, 0.0f);
            head_out += s_expert_W2[expert_idx * expert_hidden + h] * z_val;
        }
        total_out += head_out;
    }

    // ── Step 4: Smart gradient ──
    float smart_grad = g + rescale * total_out / static_cast<float>(num_heads);

    // ── Step 5: Mu EMA update ──
    // Q state: mu is int8_t packed nibbles with block_size=32 scales
    const int mu_block = idx / 32;
    const int mu_byte  = idx / 2;
    const int mu_nib   = idx % 2;
    float mu_scale = mu_scales[mu_block];
    uint8_t mu_packed = static_cast<uint8_t>(mu_q[mu_byte]);
    int mu_raw = mu_nib ? ((mu_packed >> 4) & 0x0F) : (mu_packed & 0x0F);
    float mu_val = static_cast<float>(mu_raw - 8) * mu_scale;
    mu_val = alpha * mu_val + (1.0f - alpha) * g;
    // Stochastic round mu back to INT4
    unsigned mu_rng = hash_prng(idx + global_step * 6271u);
    int mu_q_new = float_to_int8_stochastic(mu_val / fmaxf(mu_scale, 1e-12f), mu_rng);
    mu_q_new = max(-8, min(7, mu_q_new));
    uint8_t mu_byte_old = static_cast<uint8_t>(mu_q[mu_byte]);
    if (mu_nib)
        mu_q[mu_byte] = static_cast<int8_t>((mu_byte_old & 0x0F) | (((mu_q_new + 8) & 0x0F) << 4));
    else
        mu_q[mu_byte] = static_cast<int8_t>((mu_byte_old & 0xF0) | ((mu_q_new + 8) & 0x0F));

    // ── Step 6: Adam update ──
    float fg = smart_grad + lamb_eff * mu_val;
    // Q state: exp_avg/exp_avg_sq are int8 block_size=8
    const int ea_block = idx / 8;
    float ea_scale = exp_avg_scales[ea_block];
    float easq_scale = exp_avg_sq_scales[ea_block];
    float ea = static_cast<float>(exp_avg_q[idx]) * ea_scale;
    float easq = static_cast<float>(exp_avg_sq_q[idx]) * easq_scale;
    ea = beta1 * ea + (1.0f - beta1) * fg;
    easq = beta2 * easq + (1.0f - beta2) * fg * fg;
    unsigned ea_rng = hash_prng(idx * 2u + global_step * 3571u);
    unsigned easq_rng = hash_prng(idx * 2u + 1u + global_step * 3571u);
    exp_avg_q[idx] = static_cast<int8_t>(float_to_int8_stochastic(ea / fmaxf(ea_scale, 1e-12f), ea_rng));
    exp_avg_sq_q[idx] = static_cast<int8_t>(float_to_int8_stochastic(easq / fmaxf(easq_scale, 1e-12f), easq_rng));

    float step_size = lr / bc1;
    float denom = sqrtf(easq / bc2) + eps;
    float p_val = static_cast<float>(param[idx]);
    p_val = p_val * (1.0f - lr * wd_eff) - step_size * ea / denom;
    param[idx] = static_cast<scalar_t>(p_val);
}

void launch_sg2_fused_elem_Q_fp32_generic_D(
    torch::Tensor param,
    torch::Tensor grad,
    torch::Tensor sharpness,
    torch::Tensor exp_avg_q,
    torch::Tensor exp_avg_scales,
    torch::Tensor exp_avg_sq_q,
    torch::Tensor exp_avg_sq_scales,
    torch::Tensor mu_q,
    torch::Tensor mu_scales,
    torch::Tensor gru_state,
    torch::Tensor fwd_scan_out,
    torch::Tensor bwd_scan_out,
    float rescale, float alpha, float lamb_eff,
    float beta1, float beta2, float lr,
    float wd_eff, float eps, float bc1, float bc2,
    unsigned global_step,
    int d_model, int d_inner,
    int gru_hidden, int num_heads, int pk_dim,
    int expert_hidden, int num_experts
) {
    const int N = grad.numel();
    if (N == 0) return;
    const int grid = (N + 256 - 1) / 256;
    const int op_size = d_model * d_inner;
    const int gru_input_dim = 2 + 2 * d_model;
    const int gru_row_len = gru_input_dim + gru_hidden;
    const int gru_mat_size = gru_hidden * gru_row_len;
    const size_t smem_bytes = (2*op_size + 3*gru_mat_size + 3*gru_hidden
        + 3*num_experts*expert_hidden + num_experts) * sizeof(float);
    // Launch kernel (dispatch omitted — caller instantiates template)
    (void)grid; (void)smem_bytes;
}

// ===========================================================
//  sg2_fused_elem_Q_fp32_generic_D_d16_kernel  [Q/fp32/generic/D/d16]
// ===========================================================

template <typename scalar_t, int D_INNER = 16>
__launch_bounds__(256, 2)
__global__ void sg2_fused_elem_Q_fp32_generic_D_d16_kernel(
    scalar_t* __restrict__ param,
    const scalar_t* __restrict__ grad,
    const scalar_t* __restrict__ sharpness,
    int8_t* __restrict__ exp_avg_q,
    float* __restrict__ exp_avg_scales,
    int8_t* __restrict__ exp_avg_sq_q,
    float* __restrict__ exp_avg_sq_scales,
    int8_t* __restrict__ mu_q,
    float* __restrict__ mu_scales,
    __nv_bfloat16* __restrict__ gru_state,
    const float* __restrict__ fwd_scan_out,
    const float* __restrict__ bwd_scan_out,
    const float* __restrict__ out_proj_fwd_W,
    const float* __restrict__ out_proj_bwd_W,
    const float* __restrict__ gru_Wz, const float* __restrict__ gru_bz,
    const float* __restrict__ gru_Wr, const float* __restrict__ gru_br,
    const float* __restrict__ gru_Wh, const float* __restrict__ gru_bh,
    const float* __restrict__ peer_query_Ws,
    const float* __restrict__ prod_keys_A,
    const float* __restrict__ prod_keys_B,
    const float* __restrict__ expert_W1,
    const float* __restrict__ expert_b1,
    const float* __restrict__ expert_W2,
    const float* __restrict__ expert_b2,
    const float rescale, const float alpha, const float lamb_eff,
    const float beta1, const float beta2, const float lr,
    const float wd_eff, const float eps, const float bc1, const float bc2,
    const unsigned global_step,
    int* __restrict__ expert_counts,
    const int N, const int d_model,
    const int gru_hidden, const int num_heads, const int pk_dim,
    const int expert_hidden, const int num_experts
) {
    const int gru_input_dim = 2 + 2 * d_model;
    const int gru_row_len = gru_input_dim + gru_hidden;
    const int op_size = d_model * D_INNER;
    const int gru_mat_size = gru_hidden * gru_row_len;

    extern __shared__ float smem[];

    float* s_out_fwd = smem;
    float* s_out_bwd = smem + op_size;
    float* s_gru_Wz  = s_out_bwd + op_size;
    float* s_gru_Wr  = s_gru_Wz + gru_mat_size;
    float* s_gru_Wh  = s_gru_Wr + gru_mat_size;
    float* s_gru_bz  = s_gru_Wh + gru_mat_size;
    float* s_gru_br  = s_gru_bz + gru_hidden;
    float* s_gru_bh  = s_gru_br + gru_hidden;
    float* s_expert_W1 = s_gru_bh + gru_hidden;
    float* s_expert_b1 = s_expert_W1 + num_experts * expert_hidden;
    float* s_expert_W2 = s_expert_b1 + num_experts * expert_hidden;
    float* s_expert_b2 = s_expert_W2 + num_experts * expert_hidden;

    const int tid = threadIdx.x;
    const int block_size = blockDim.x;

    // Load out_proj weights
    for (int i = tid; i < 2 * op_size; i += block_size) {
        if (i < op_size) smem[i] = out_proj_fwd_W[i];
        else smem[i] = out_proj_bwd_W[i - op_size];
    }
    // Load GRU weights
    const float* gru_gmem[] = {gru_Wz, gru_Wr, gru_Wh, gru_bz, gru_br, gru_bh};
    int gru_sizes[] = {gru_mat_size, gru_mat_size, gru_mat_size, gru_hidden, gru_hidden, gru_hidden};
    float* gru_dst = s_gru_Wz;
    int gru_offset = 0;
    for (int seg = 0; seg < 6; seg++) {
        for (int i = tid; i < gru_sizes[seg]; i += block_size)
            gru_dst[gru_offset + i] = gru_gmem[seg][i];
        gru_offset += gru_sizes[seg];
    }

    for (int i = tid; i < num_experts * expert_hidden; i += block_size) {
        s_expert_W1[i] = expert_W1[i];
        s_expert_b1[i] = expert_b1[i];
        s_expert_W2[i] = expert_W2[i];
    }
    for (int i = tid; i < num_experts; i += block_size) {
        s_expert_b2[i] = expert_b2[i];
    }
    __syncthreads();

    // Per-element processing
    const int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx >= N) return;

    float g = static_cast<float>(grad[idx]);
    float s = static_cast<float>(sharpness[idx]);
    if (!isfinite(g)) g = 0.0f;
    if (!isfinite(s)) s = 0.0f;
    const int half_d = d_model / 2;
    const int peer_input_dim = gru_hidden + 2 * d_model + 2;

    // ── Step 1: Mamba out_proj ──
    float fwd_scan[MAX_D_INNER], bwd_scan[MAX_D_INNER];
    #pragma unroll
    for (int j = 0; j < D_INNER; j += 4) {
        float4 fwd4 = *reinterpret_cast<const float4*>(&fwd_scan_out[idx * D_INNER + j]);
        float4 bwd4 = *reinterpret_cast<const float4*>(&bwd_scan_out[idx * D_INNER + j]);
        fwd_scan[j]   = fwd4.x; fwd_scan[j+1] = fwd4.y;
        fwd_scan[j+2] = fwd4.z; fwd_scan[j+3] = fwd4.w;
        bwd_scan[j]   = bwd4.x; bwd_scan[j+1] = bwd4.y;
        bwd_scan[j+2] = bwd4.z; bwd_scan[j+3] = bwd4.w;
    }

    float fwd_ctx[MAX_D_MODEL], bwd_ctx[MAX_D_MODEL];
    for (int d = 0; d < d_model; d++) {
        float fwd_val = 0.0f, bwd_val = 0.0f;
        #pragma unroll
        for (int j = 0; j < D_INNER; j++) {
            fwd_val += s_out_fwd[d * D_INNER + j] * fwd_scan[j];
            bwd_val += s_out_bwd[d * D_INNER + j] * bwd_scan[j];
        }
        fwd_ctx[d] = fwd_val;
        bwd_ctx[d] = bwd_val;
    }

    // ── Step 2: GRU update ──
    float h_old[MAX_GRU_HIDDEN];
    for (int j = 0; j < gru_hidden; j++)
        h_old[j] = static_cast<float>(gru_state[idx * gru_hidden + j]);

    float z_gate[MAX_GRU_HIDDEN], r_gate[MAX_GRU_HIDDEN];
    for (int j = 0; j < gru_hidden; j++) {
        float val_z = s_gru_bz[j];
        float val_r = s_gru_br[j];
        val_z += s_gru_Wz[j * gru_row_len + 0] * g;
        val_z += s_gru_Wz[j * gru_row_len + 1] * s;
        val_r += s_gru_Wr[j * gru_row_len + 0] * g;
        val_r += s_gru_Wr[j * gru_row_len + 1] * s;
        int off = 2;
        for (int d = 0; d < d_model; d++) {
            val_z += s_gru_Wz[j * gru_row_len + off + d] * fwd_ctx[d];
            val_r += s_gru_Wr[j * gru_row_len + off + d] * fwd_ctx[d];
        }
        off += d_model;
        for (int d = 0; d < d_model; d++) {
            val_z += s_gru_Wz[j * gru_row_len + off + d] * bwd_ctx[d];
            val_r += s_gru_Wr[j * gru_row_len + off + d] * bwd_ctx[d];
        }
        off += d_model;
        for (int k = 0; k < gru_hidden; k++) {
            val_z += s_gru_Wz[j * gru_row_len + off + k] * h_old[k];
            val_r += s_gru_Wr[j * gru_row_len + off + k] * h_old[k];
        }
        z_gate[j] = 1.0f / (1.0f + expf(-val_z));
        r_gate[j] = 1.0f / (1.0f + expf(-val_r));
    }

    float h_new[MAX_GRU_HIDDEN];
    for (int j = 0; j < gru_hidden; j++) {
        float val = s_gru_bh[j];
        val += s_gru_Wh[j * gru_row_len + 0] * g;
        val += s_gru_Wh[j * gru_row_len + 1] * s;
        int off = 2;
        for (int d = 0; d < d_model; d++)
            val += s_gru_Wh[j * gru_row_len + off + d] * fwd_ctx[d];
        off += d_model;
        for (int d = 0; d < d_model; d++)
            val += s_gru_Wh[j * gru_row_len + off + d] * bwd_ctx[d];
        off += d_model;
        for (int k = 0; k < gru_hidden; k++)
            val += s_gru_Wh[j * gru_row_len + off + k] * (r_gate[k] * h_old[k]);
        float h_tilde = tanhf(val);
        h_new[j] = (1.0f - z_gate[j]) * h_old[j] + z_gate[j] * h_tilde;
    }

    unsigned gru_rng = hash_prng(idx * gru_hidden + global_step * 7919u);
    for (int j = 0; j < gru_hidden; j++) {
        gru_state[idx * gru_hidden + j] = float_to_bf16_stochastic(h_new[j], gru_rng);
        gru_rng = hash_prng(gru_rng + j);
    }

    // ── Step 3: Multi-head PEER routing + expert MLP ──
    float total_out = 0.0f;
    for (int head = 0; head < num_heads; head++) {
        const float* pq_W = peer_query_Ws + head * d_model * peer_input_dim;
        float query[MAX_D_MODEL];
        for (int d = 0; d < d_model; d++) {
            float val = 0.0f;
            int poff = 0;
            for (int k = 0; k < gru_hidden; k++)
                val += pq_W[d * peer_input_dim + poff + k] * h_new[k];
            poff += gru_hidden;
            for (int k = 0; k < d_model; k++)
                val += pq_W[d * peer_input_dim + poff + k] * fwd_ctx[k];
            poff += d_model;
            for (int k = 0; k < d_model; k++)
                val += pq_W[d * peer_input_dim + poff + k] * bwd_ctx[k];
            poff += d_model;
            val += pq_W[d * peer_input_dim + poff] * g;
            val += pq_W[d * peer_input_dim + poff + 1] * s;
            query[d] = val;
        }

        // Product-key argmax
        const float* keys_A = prod_keys_A + head * pk_dim * half_d;
        const float* keys_B = prod_keys_B + head * pk_dim * half_d;
        int best_a = 0; float best_sa = -1e30f;
        for (int k = 0; k < pk_dim; k++) {
            float dot = 0.0f;
            for (int d = 0; d < half_d; d++)
                dot += query[d] * LDG(&keys_A[k * half_d + d]);
            if (dot > best_sa) { best_sa = dot; best_a = k; }
        }
        int best_b = 0; float best_sb = -1e30f;
        for (int k = 0; k < pk_dim; k++) {
            float dot = 0.0f;
            for (int d = 0; d < half_d; d++)
                dot += query[half_d + d] * LDG(&keys_B[k * half_d + d]);
            if (dot > best_sb) { best_sb = dot; best_b = k; }
        }
        int expert_idx = best_a * pk_dim + best_b;
        if (expert_idx >= num_experts) expert_idx = num_experts - 1;
        if (expert_counts != nullptr)
            atomicAdd(&expert_counts[expert_idx], 1);

        // Expert MLP: ReLU hidden layer
        float head_out = s_expert_b2[expert_idx];
        for (int h = 0; h < expert_hidden; h++) {
            float z_val = s_expert_W1[expert_idx * expert_hidden + h] * g
                        + s_expert_b1[expert_idx * expert_hidden + h];
            z_val = fmaxf(z_val, 0.0f);
            head_out += s_expert_W2[expert_idx * expert_hidden + h] * z_val;
        }
        total_out += head_out;
    }

    // ── Step 4: Smart gradient ──
    float smart_grad = g + rescale * total_out / static_cast<float>(num_heads);

    // ── Step 5: Mu EMA update ──
    // Q state: mu is int8_t packed nibbles with block_size=32 scales
    const int mu_block = idx / 32;
    const int mu_byte  = idx / 2;
    const int mu_nib   = idx % 2;
    float mu_scale = mu_scales[mu_block];
    uint8_t mu_packed = static_cast<uint8_t>(mu_q[mu_byte]);
    int mu_raw = mu_nib ? ((mu_packed >> 4) & 0x0F) : (mu_packed & 0x0F);
    float mu_val = static_cast<float>(mu_raw - 8) * mu_scale;
    mu_val = alpha * mu_val + (1.0f - alpha) * g;
    // Stochastic round mu back to INT4
    unsigned mu_rng = hash_prng(idx + global_step * 6271u);
    int mu_q_new = float_to_int8_stochastic(mu_val / fmaxf(mu_scale, 1e-12f), mu_rng);
    mu_q_new = max(-8, min(7, mu_q_new));
    uint8_t mu_byte_old = static_cast<uint8_t>(mu_q[mu_byte]);
    if (mu_nib)
        mu_q[mu_byte] = static_cast<int8_t>((mu_byte_old & 0x0F) | (((mu_q_new + 8) & 0x0F) << 4));
    else
        mu_q[mu_byte] = static_cast<int8_t>((mu_byte_old & 0xF0) | ((mu_q_new + 8) & 0x0F));

    // ── Step 6: Adam update ──
    float fg = smart_grad + lamb_eff * mu_val;
    // Q state: exp_avg/exp_avg_sq are int8 block_size=8
    const int ea_block = idx / 8;
    float ea_scale = exp_avg_scales[ea_block];
    float easq_scale = exp_avg_sq_scales[ea_block];
    float ea = static_cast<float>(exp_avg_q[idx]) * ea_scale;
    float easq = static_cast<float>(exp_avg_sq_q[idx]) * easq_scale;
    ea = beta1 * ea + (1.0f - beta1) * fg;
    easq = beta2 * easq + (1.0f - beta2) * fg * fg;
    unsigned ea_rng = hash_prng(idx * 2u + global_step * 3571u);
    unsigned easq_rng = hash_prng(idx * 2u + 1u + global_step * 3571u);
    exp_avg_q[idx] = static_cast<int8_t>(float_to_int8_stochastic(ea / fmaxf(ea_scale, 1e-12f), ea_rng));
    exp_avg_sq_q[idx] = static_cast<int8_t>(float_to_int8_stochastic(easq / fmaxf(easq_scale, 1e-12f), easq_rng));

    float step_size = lr / bc1;
    float denom = sqrtf(easq / bc2) + eps;
    float p_val = static_cast<float>(param[idx]);
    p_val = p_val * (1.0f - lr * wd_eff) - step_size * ea / denom;
    param[idx] = static_cast<scalar_t>(p_val);
}

void launch_sg2_fused_elem_Q_fp32_generic_D_d16(
    torch::Tensor param,
    torch::Tensor grad,
    torch::Tensor sharpness,
    torch::Tensor exp_avg_q,
    torch::Tensor exp_avg_scales,
    torch::Tensor exp_avg_sq_q,
    torch::Tensor exp_avg_sq_scales,
    torch::Tensor mu_q,
    torch::Tensor mu_scales,
    torch::Tensor gru_state,
    torch::Tensor fwd_scan_out,
    torch::Tensor bwd_scan_out,
    float rescale, float alpha, float lamb_eff,
    float beta1, float beta2, float lr,
    float wd_eff, float eps, float bc1, float bc2,
    unsigned global_step,
    int d_model, int d_inner,
    int gru_hidden, int num_heads, int pk_dim,
    int expert_hidden, int num_experts
) {
    const int N = grad.numel();
    if (N == 0) return;
    const int grid = (N + 256 - 1) / 256;
    const int op_size = d_model * 16;
    const int gru_input_dim = 2 + 2 * d_model;
    const int gru_row_len = gru_input_dim + gru_hidden;
    const int gru_mat_size = gru_hidden * gru_row_len;
    const size_t smem_bytes = (2*op_size + 3*gru_mat_size + 3*gru_hidden
        + 3*num_experts*expert_hidden + num_experts) * sizeof(float);
    // Launch kernel (dispatch omitted — caller instantiates template)
    (void)grid; (void)smem_bytes;
}

// ===========================================================
//  sg2_fused_elem_Q_fp32_generic_M_kernel  [Q/fp32/generic/M]
// ===========================================================

template <typename scalar_t>
__launch_bounds__(256, 2)
__global__ void sg2_fused_elem_Q_fp32_generic_M_kernel(
    scalar_t* __restrict__ param,
    const scalar_t* __restrict__ grad,
    const scalar_t* __restrict__ sharpness,
    int8_t* __restrict__ exp_avg_q,
    float* __restrict__ exp_avg_scales,
    int8_t* __restrict__ exp_avg_sq_q,
    float* __restrict__ exp_avg_sq_scales,
    int8_t* __restrict__ mu_q,
    float* __restrict__ mu_scales,
    __nv_bfloat16* __restrict__ gru_state,
    const float* __restrict__ fwd_scan_out,
    const float* __restrict__ bwd_scan_out,
    const float* __restrict__ out_proj_fwd_W,
    const float* __restrict__ out_proj_bwd_W,
    const float* __restrict__ gru_Wz, const float* __restrict__ gru_bz,
    const float* __restrict__ gru_Wr, const float* __restrict__ gru_br,
    const float* __restrict__ gru_Wh, const float* __restrict__ gru_bh,
    const float* __restrict__ peer_query_Ws,
    const float* __restrict__ prod_keys_A,
    const float* __restrict__ prod_keys_B,
    const float* __restrict__ expert_W1,
    const float* __restrict__ expert_b1,
    const float* __restrict__ expert_W2,
    const float* __restrict__ expert_b2,
    const float rescale, const float alpha, const float lamb_eff,
    const float beta1, const float beta2, const float lr,
    const float wd_eff, const float eps, const float bc1, const float bc2,
    const unsigned global_step,
    const bool* __restrict__ active_mask,
    int* __restrict__ expert_counts,
    const int N, const int d_model, const int d_inner,
    const int gru_hidden, const int num_heads, const int pk_dim,
    const int expert_hidden, const int num_experts
) {
    const int gru_input_dim = 2 + 2 * d_model;
    const int gru_row_len = gru_input_dim + gru_hidden;
    const int op_size = d_model * d_inner;
    const int gru_mat_size = gru_hidden * gru_row_len;

    extern __shared__ float smem[];

    float* s_out_fwd = smem;
    float* s_out_bwd = smem + op_size;
    float* s_gru_Wz  = s_out_bwd + op_size;
    float* s_gru_Wr  = s_gru_Wz + gru_mat_size;
    float* s_gru_Wh  = s_gru_Wr + gru_mat_size;
    float* s_gru_bz  = s_gru_Wh + gru_mat_size;
    float* s_gru_br  = s_gru_bz + gru_hidden;
    float* s_gru_bh  = s_gru_br + gru_hidden;
    float* s_expert_W1 = s_gru_bh + gru_hidden;
    float* s_expert_b1 = s_expert_W1 + num_experts * expert_hidden;
    float* s_expert_W2 = s_expert_b1 + num_experts * expert_hidden;
    float* s_expert_b2 = s_expert_W2 + num_experts * expert_hidden;

    const int tid = threadIdx.x;
    const int block_size = blockDim.x;

    // Load out_proj weights
    for (int i = tid; i < 2 * op_size; i += block_size) {
        if (i < op_size) smem[i] = out_proj_fwd_W[i];
        else smem[i] = out_proj_bwd_W[i - op_size];
    }
    // Load GRU weights
    const float* gru_gmem[] = {gru_Wz, gru_Wr, gru_Wh, gru_bz, gru_br, gru_bh};
    int gru_sizes[] = {gru_mat_size, gru_mat_size, gru_mat_size, gru_hidden, gru_hidden, gru_hidden};
    float* gru_dst = s_gru_Wz;
    int gru_offset = 0;
    for (int seg = 0; seg < 6; seg++) {
        for (int i = tid; i < gru_sizes[seg]; i += block_size)
            gru_dst[gru_offset + i] = gru_gmem[seg][i];
        gru_offset += gru_sizes[seg];
    }

    for (int i = tid; i < num_experts * expert_hidden; i += block_size) {
        s_expert_W1[i] = expert_W1[i];
        s_expert_b1[i] = expert_b1[i];
        s_expert_W2[i] = expert_W2[i];
    }
    for (int i = tid; i < num_experts; i += block_size) {
        s_expert_b2[i] = expert_b2[i];
    }
    __syncthreads();

    // Per-element processing
    const int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx >= N) return;

    // MoE early-exit
    if (!active_mask[idx]) return;

    float g = static_cast<float>(grad[idx]);
    float s = static_cast<float>(sharpness[idx]);
    if (!isfinite(g)) g = 0.0f;
    if (!isfinite(s)) s = 0.0f;
    const int half_d = d_model / 2;
    const int peer_input_dim = gru_hidden + 2 * d_model + 2;

    // ── Step 1: Mamba out_proj ──
    float fwd_scan[MAX_D_INNER], bwd_scan[MAX_D_INNER];
    for (int j = 0; j < d_inner; j += 4) {
        float4 fwd4 = *reinterpret_cast<const float4*>(&fwd_scan_out[idx * d_inner + j]);
        float4 bwd4 = *reinterpret_cast<const float4*>(&bwd_scan_out[idx * d_inner + j]);
        fwd_scan[j]   = fwd4.x; fwd_scan[j+1] = fwd4.y;
        fwd_scan[j+2] = fwd4.z; fwd_scan[j+3] = fwd4.w;
        bwd_scan[j]   = bwd4.x; bwd_scan[j+1] = bwd4.y;
        bwd_scan[j+2] = bwd4.z; bwd_scan[j+3] = bwd4.w;
    }

    float fwd_ctx[MAX_D_MODEL], bwd_ctx[MAX_D_MODEL];
    for (int d = 0; d < d_model; d++) {
        float fwd_val = 0.0f, bwd_val = 0.0f;
        for (int j = 0; j < d_inner; j++) {
            fwd_val += s_out_fwd[d * d_inner + j] * fwd_scan[j];
            bwd_val += s_out_bwd[d * d_inner + j] * bwd_scan[j];
        }
        fwd_ctx[d] = fwd_val;
        bwd_ctx[d] = bwd_val;
    }

    // ── Step 2: GRU update ──
    float h_old[MAX_GRU_HIDDEN];
    for (int j = 0; j < gru_hidden; j++)
        h_old[j] = static_cast<float>(gru_state[idx * gru_hidden + j]);

    float z_gate[MAX_GRU_HIDDEN], r_gate[MAX_GRU_HIDDEN];
    for (int j = 0; j < gru_hidden; j++) {
        float val_z = s_gru_bz[j];
        float val_r = s_gru_br[j];
        val_z += s_gru_Wz[j * gru_row_len + 0] * g;
        val_z += s_gru_Wz[j * gru_row_len + 1] * s;
        val_r += s_gru_Wr[j * gru_row_len + 0] * g;
        val_r += s_gru_Wr[j * gru_row_len + 1] * s;
        int off = 2;
        for (int d = 0; d < d_model; d++) {
            val_z += s_gru_Wz[j * gru_row_len + off + d] * fwd_ctx[d];
            val_r += s_gru_Wr[j * gru_row_len + off + d] * fwd_ctx[d];
        }
        off += d_model;
        for (int d = 0; d < d_model; d++) {
            val_z += s_gru_Wz[j * gru_row_len + off + d] * bwd_ctx[d];
            val_r += s_gru_Wr[j * gru_row_len + off + d] * bwd_ctx[d];
        }
        off += d_model;
        for (int k = 0; k < gru_hidden; k++) {
            val_z += s_gru_Wz[j * gru_row_len + off + k] * h_old[k];
            val_r += s_gru_Wr[j * gru_row_len + off + k] * h_old[k];
        }
        z_gate[j] = 1.0f / (1.0f + expf(-val_z));
        r_gate[j] = 1.0f / (1.0f + expf(-val_r));
    }

    float h_new[MAX_GRU_HIDDEN];
    for (int j = 0; j < gru_hidden; j++) {
        float val = s_gru_bh[j];
        val += s_gru_Wh[j * gru_row_len + 0] * g;
        val += s_gru_Wh[j * gru_row_len + 1] * s;
        int off = 2;
        for (int d = 0; d < d_model; d++)
            val += s_gru_Wh[j * gru_row_len + off + d] * fwd_ctx[d];
        off += d_model;
        for (int d = 0; d < d_model; d++)
            val += s_gru_Wh[j * gru_row_len + off + d] * bwd_ctx[d];
        off += d_model;
        for (int k = 0; k < gru_hidden; k++)
            val += s_gru_Wh[j * gru_row_len + off + k] * (r_gate[k] * h_old[k]);
        float h_tilde = tanhf(val);
        h_new[j] = (1.0f - z_gate[j]) * h_old[j] + z_gate[j] * h_tilde;
    }

    unsigned gru_rng = hash_prng(idx * gru_hidden + global_step * 7919u);
    for (int j = 0; j < gru_hidden; j++) {
        gru_state[idx * gru_hidden + j] = float_to_bf16_stochastic(h_new[j], gru_rng);
        gru_rng = hash_prng(gru_rng + j);
    }

    // ── Step 3: Multi-head PEER routing + expert MLP ──
    float total_out = 0.0f;
    for (int head = 0; head < num_heads; head++) {
        const float* pq_W = peer_query_Ws + head * d_model * peer_input_dim;
        float query[MAX_D_MODEL];
        for (int d = 0; d < d_model; d++) {
            float val = 0.0f;
            int poff = 0;
            for (int k = 0; k < gru_hidden; k++)
                val += pq_W[d * peer_input_dim + poff + k] * h_new[k];
            poff += gru_hidden;
            for (int k = 0; k < d_model; k++)
                val += pq_W[d * peer_input_dim + poff + k] * fwd_ctx[k];
            poff += d_model;
            for (int k = 0; k < d_model; k++)
                val += pq_W[d * peer_input_dim + poff + k] * bwd_ctx[k];
            poff += d_model;
            val += pq_W[d * peer_input_dim + poff] * g;
            val += pq_W[d * peer_input_dim + poff + 1] * s;
            query[d] = val;
        }

        // Product-key argmax
        const float* keys_A = prod_keys_A + head * pk_dim * half_d;
        const float* keys_B = prod_keys_B + head * pk_dim * half_d;
        int best_a = 0; float best_sa = -1e30f;
        for (int k = 0; k < pk_dim; k++) {
            float dot = 0.0f;
            for (int d = 0; d < half_d; d++)
                dot += query[d] * LDG(&keys_A[k * half_d + d]);
            if (dot > best_sa) { best_sa = dot; best_a = k; }
        }
        int best_b = 0; float best_sb = -1e30f;
        for (int k = 0; k < pk_dim; k++) {
            float dot = 0.0f;
            for (int d = 0; d < half_d; d++)
                dot += query[half_d + d] * LDG(&keys_B[k * half_d + d]);
            if (dot > best_sb) { best_sb = dot; best_b = k; }
        }
        int expert_idx = best_a * pk_dim + best_b;
        if (expert_idx >= num_experts) expert_idx = num_experts - 1;
        if (expert_counts != nullptr)
            atomicAdd(&expert_counts[expert_idx], 1);

        // Expert MLP: ReLU hidden layer
        float head_out = s_expert_b2[expert_idx];
        for (int h = 0; h < expert_hidden; h++) {
            float z_val = s_expert_W1[expert_idx * expert_hidden + h] * g
                        + s_expert_b1[expert_idx * expert_hidden + h];
            z_val = fmaxf(z_val, 0.0f);
            head_out += s_expert_W2[expert_idx * expert_hidden + h] * z_val;
        }
        total_out += head_out;
    }

    // ── Step 4: Smart gradient ──
    float smart_grad = g + rescale * total_out / static_cast<float>(num_heads);

    // ── Step 5: Mu EMA update ──
    // Q state: mu is int8_t packed nibbles with block_size=32 scales
    const int mu_block = idx / 32;
    const int mu_byte  = idx / 2;
    const int mu_nib   = idx % 2;
    float mu_scale = mu_scales[mu_block];
    uint8_t mu_packed = static_cast<uint8_t>(mu_q[mu_byte]);
    int mu_raw = mu_nib ? ((mu_packed >> 4) & 0x0F) : (mu_packed & 0x0F);
    float mu_val = static_cast<float>(mu_raw - 8) * mu_scale;
    mu_val = alpha * mu_val + (1.0f - alpha) * g;
    // Stochastic round mu back to INT4
    unsigned mu_rng = hash_prng(idx + global_step * 6271u);
    int mu_q_new = float_to_int8_stochastic(mu_val / fmaxf(mu_scale, 1e-12f), mu_rng);
    mu_q_new = max(-8, min(7, mu_q_new));
    uint8_t mu_byte_old = static_cast<uint8_t>(mu_q[mu_byte]);
    if (mu_nib)
        mu_q[mu_byte] = static_cast<int8_t>((mu_byte_old & 0x0F) | (((mu_q_new + 8) & 0x0F) << 4));
    else
        mu_q[mu_byte] = static_cast<int8_t>((mu_byte_old & 0xF0) | ((mu_q_new + 8) & 0x0F));

    // ── Step 6: Adam update ──
    float fg = smart_grad + lamb_eff * mu_val;
    // Q state: exp_avg/exp_avg_sq are int8 block_size=8
    const int ea_block = idx / 8;
    float ea_scale = exp_avg_scales[ea_block];
    float easq_scale = exp_avg_sq_scales[ea_block];
    float ea = static_cast<float>(exp_avg_q[idx]) * ea_scale;
    float easq = static_cast<float>(exp_avg_sq_q[idx]) * easq_scale;
    ea = beta1 * ea + (1.0f - beta1) * fg;
    easq = beta2 * easq + (1.0f - beta2) * fg * fg;
    unsigned ea_rng = hash_prng(idx * 2u + global_step * 3571u);
    unsigned easq_rng = hash_prng(idx * 2u + 1u + global_step * 3571u);
    exp_avg_q[idx] = static_cast<int8_t>(float_to_int8_stochastic(ea / fmaxf(ea_scale, 1e-12f), ea_rng));
    exp_avg_sq_q[idx] = static_cast<int8_t>(float_to_int8_stochastic(easq / fmaxf(easq_scale, 1e-12f), easq_rng));

    float step_size = lr / bc1;
    float denom = sqrtf(easq / bc2) + eps;
    float p_val = static_cast<float>(param[idx]);
    p_val = p_val * (1.0f - lr * wd_eff) - step_size * ea / denom;
    param[idx] = static_cast<scalar_t>(p_val);
}

void launch_sg2_fused_elem_Q_fp32_generic_M(
    torch::Tensor param,
    torch::Tensor grad,
    torch::Tensor sharpness,
    torch::Tensor exp_avg_q,
    torch::Tensor exp_avg_scales,
    torch::Tensor exp_avg_sq_q,
    torch::Tensor exp_avg_sq_scales,
    torch::Tensor mu_q,
    torch::Tensor mu_scales,
    torch::Tensor gru_state,
    torch::Tensor fwd_scan_out,
    torch::Tensor bwd_scan_out,
    float rescale, float alpha, float lamb_eff,
    float beta1, float beta2, float lr,
    float wd_eff, float eps, float bc1, float bc2,
    unsigned global_step,
    torch::Tensor active_mask,
    int d_model, int d_inner,
    int gru_hidden, int num_heads, int pk_dim,
    int expert_hidden, int num_experts
) {
    const int N = grad.numel();
    if (N == 0) return;
    const int grid = (N + 256 - 1) / 256;
    const int op_size = d_model * d_inner;
    const int gru_input_dim = 2 + 2 * d_model;
    const int gru_row_len = gru_input_dim + gru_hidden;
    const int gru_mat_size = gru_hidden * gru_row_len;
    const size_t smem_bytes = (2*op_size + 3*gru_mat_size + 3*gru_hidden
        + 3*num_experts*expert_hidden + num_experts) * sizeof(float);
    // Launch kernel (dispatch omitted — caller instantiates template)
    (void)grid; (void)smem_bytes;
}

// ===========================================================
//  sg2_fused_elem_Q_fp32_generic_M_d16_kernel  [Q/fp32/generic/M/d16]
// ===========================================================

template <typename scalar_t, int D_INNER = 16>
__launch_bounds__(256, 2)
__global__ void sg2_fused_elem_Q_fp32_generic_M_d16_kernel(
    scalar_t* __restrict__ param,
    const scalar_t* __restrict__ grad,
    const scalar_t* __restrict__ sharpness,
    int8_t* __restrict__ exp_avg_q,
    float* __restrict__ exp_avg_scales,
    int8_t* __restrict__ exp_avg_sq_q,
    float* __restrict__ exp_avg_sq_scales,
    int8_t* __restrict__ mu_q,
    float* __restrict__ mu_scales,
    __nv_bfloat16* __restrict__ gru_state,
    const float* __restrict__ fwd_scan_out,
    const float* __restrict__ bwd_scan_out,
    const float* __restrict__ out_proj_fwd_W,
    const float* __restrict__ out_proj_bwd_W,
    const float* __restrict__ gru_Wz, const float* __restrict__ gru_bz,
    const float* __restrict__ gru_Wr, const float* __restrict__ gru_br,
    const float* __restrict__ gru_Wh, const float* __restrict__ gru_bh,
    const float* __restrict__ peer_query_Ws,
    const float* __restrict__ prod_keys_A,
    const float* __restrict__ prod_keys_B,
    const float* __restrict__ expert_W1,
    const float* __restrict__ expert_b1,
    const float* __restrict__ expert_W2,
    const float* __restrict__ expert_b2,
    const float rescale, const float alpha, const float lamb_eff,
    const float beta1, const float beta2, const float lr,
    const float wd_eff, const float eps, const float bc1, const float bc2,
    const unsigned global_step,
    const bool* __restrict__ active_mask,
    int* __restrict__ expert_counts,
    const int N, const int d_model,
    const int gru_hidden, const int num_heads, const int pk_dim,
    const int expert_hidden, const int num_experts
) {
    const int gru_input_dim = 2 + 2 * d_model;
    const int gru_row_len = gru_input_dim + gru_hidden;
    const int op_size = d_model * D_INNER;
    const int gru_mat_size = gru_hidden * gru_row_len;

    extern __shared__ float smem[];

    float* s_out_fwd = smem;
    float* s_out_bwd = smem + op_size;
    float* s_gru_Wz  = s_out_bwd + op_size;
    float* s_gru_Wr  = s_gru_Wz + gru_mat_size;
    float* s_gru_Wh  = s_gru_Wr + gru_mat_size;
    float* s_gru_bz  = s_gru_Wh + gru_mat_size;
    float* s_gru_br  = s_gru_bz + gru_hidden;
    float* s_gru_bh  = s_gru_br + gru_hidden;
    float* s_expert_W1 = s_gru_bh + gru_hidden;
    float* s_expert_b1 = s_expert_W1 + num_experts * expert_hidden;
    float* s_expert_W2 = s_expert_b1 + num_experts * expert_hidden;
    float* s_expert_b2 = s_expert_W2 + num_experts * expert_hidden;

    const int tid = threadIdx.x;
    const int block_size = blockDim.x;

    // Load out_proj weights
    for (int i = tid; i < 2 * op_size; i += block_size) {
        if (i < op_size) smem[i] = out_proj_fwd_W[i];
        else smem[i] = out_proj_bwd_W[i - op_size];
    }
    // Load GRU weights
    const float* gru_gmem[] = {gru_Wz, gru_Wr, gru_Wh, gru_bz, gru_br, gru_bh};
    int gru_sizes[] = {gru_mat_size, gru_mat_size, gru_mat_size, gru_hidden, gru_hidden, gru_hidden};
    float* gru_dst = s_gru_Wz;
    int gru_offset = 0;
    for (int seg = 0; seg < 6; seg++) {
        for (int i = tid; i < gru_sizes[seg]; i += block_size)
            gru_dst[gru_offset + i] = gru_gmem[seg][i];
        gru_offset += gru_sizes[seg];
    }

    for (int i = tid; i < num_experts * expert_hidden; i += block_size) {
        s_expert_W1[i] = expert_W1[i];
        s_expert_b1[i] = expert_b1[i];
        s_expert_W2[i] = expert_W2[i];
    }
    for (int i = tid; i < num_experts; i += block_size) {
        s_expert_b2[i] = expert_b2[i];
    }
    __syncthreads();

    // Per-element processing
    const int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx >= N) return;

    // MoE early-exit
    if (!active_mask[idx]) return;

    float g = static_cast<float>(grad[idx]);
    float s = static_cast<float>(sharpness[idx]);
    if (!isfinite(g)) g = 0.0f;
    if (!isfinite(s)) s = 0.0f;
    const int half_d = d_model / 2;
    const int peer_input_dim = gru_hidden + 2 * d_model + 2;

    // ── Step 1: Mamba out_proj ──
    float fwd_scan[MAX_D_INNER], bwd_scan[MAX_D_INNER];
    #pragma unroll
    for (int j = 0; j < D_INNER; j += 4) {
        float4 fwd4 = *reinterpret_cast<const float4*>(&fwd_scan_out[idx * D_INNER + j]);
        float4 bwd4 = *reinterpret_cast<const float4*>(&bwd_scan_out[idx * D_INNER + j]);
        fwd_scan[j]   = fwd4.x; fwd_scan[j+1] = fwd4.y;
        fwd_scan[j+2] = fwd4.z; fwd_scan[j+3] = fwd4.w;
        bwd_scan[j]   = bwd4.x; bwd_scan[j+1] = bwd4.y;
        bwd_scan[j+2] = bwd4.z; bwd_scan[j+3] = bwd4.w;
    }

    float fwd_ctx[MAX_D_MODEL], bwd_ctx[MAX_D_MODEL];
    for (int d = 0; d < d_model; d++) {
        float fwd_val = 0.0f, bwd_val = 0.0f;
        #pragma unroll
        for (int j = 0; j < D_INNER; j++) {
            fwd_val += s_out_fwd[d * D_INNER + j] * fwd_scan[j];
            bwd_val += s_out_bwd[d * D_INNER + j] * bwd_scan[j];
        }
        fwd_ctx[d] = fwd_val;
        bwd_ctx[d] = bwd_val;
    }

    // ── Step 2: GRU update ──
    float h_old[MAX_GRU_HIDDEN];
    for (int j = 0; j < gru_hidden; j++)
        h_old[j] = static_cast<float>(gru_state[idx * gru_hidden + j]);

    float z_gate[MAX_GRU_HIDDEN], r_gate[MAX_GRU_HIDDEN];
    for (int j = 0; j < gru_hidden; j++) {
        float val_z = s_gru_bz[j];
        float val_r = s_gru_br[j];
        val_z += s_gru_Wz[j * gru_row_len + 0] * g;
        val_z += s_gru_Wz[j * gru_row_len + 1] * s;
        val_r += s_gru_Wr[j * gru_row_len + 0] * g;
        val_r += s_gru_Wr[j * gru_row_len + 1] * s;
        int off = 2;
        for (int d = 0; d < d_model; d++) {
            val_z += s_gru_Wz[j * gru_row_len + off + d] * fwd_ctx[d];
            val_r += s_gru_Wr[j * gru_row_len + off + d] * fwd_ctx[d];
        }
        off += d_model;
        for (int d = 0; d < d_model; d++) {
            val_z += s_gru_Wz[j * gru_row_len + off + d] * bwd_ctx[d];
            val_r += s_gru_Wr[j * gru_row_len + off + d] * bwd_ctx[d];
        }
        off += d_model;
        for (int k = 0; k < gru_hidden; k++) {
            val_z += s_gru_Wz[j * gru_row_len + off + k] * h_old[k];
            val_r += s_gru_Wr[j * gru_row_len + off + k] * h_old[k];
        }
        z_gate[j] = 1.0f / (1.0f + expf(-val_z));
        r_gate[j] = 1.0f / (1.0f + expf(-val_r));
    }

    float h_new[MAX_GRU_HIDDEN];
    for (int j = 0; j < gru_hidden; j++) {
        float val = s_gru_bh[j];
        val += s_gru_Wh[j * gru_row_len + 0] * g;
        val += s_gru_Wh[j * gru_row_len + 1] * s;
        int off = 2;
        for (int d = 0; d < d_model; d++)
            val += s_gru_Wh[j * gru_row_len + off + d] * fwd_ctx[d];
        off += d_model;
        for (int d = 0; d < d_model; d++)
            val += s_gru_Wh[j * gru_row_len + off + d] * bwd_ctx[d];
        off += d_model;
        for (int k = 0; k < gru_hidden; k++)
            val += s_gru_Wh[j * gru_row_len + off + k] * (r_gate[k] * h_old[k]);
        float h_tilde = tanhf(val);
        h_new[j] = (1.0f - z_gate[j]) * h_old[j] + z_gate[j] * h_tilde;
    }

    unsigned gru_rng = hash_prng(idx * gru_hidden + global_step * 7919u);
    for (int j = 0; j < gru_hidden; j++) {
        gru_state[idx * gru_hidden + j] = float_to_bf16_stochastic(h_new[j], gru_rng);
        gru_rng = hash_prng(gru_rng + j);
    }

    // ── Step 3: Multi-head PEER routing + expert MLP ──
    float total_out = 0.0f;
    for (int head = 0; head < num_heads; head++) {
        const float* pq_W = peer_query_Ws + head * d_model * peer_input_dim;
        float query[MAX_D_MODEL];
        for (int d = 0; d < d_model; d++) {
            float val = 0.0f;
            int poff = 0;
            for (int k = 0; k < gru_hidden; k++)
                val += pq_W[d * peer_input_dim + poff + k] * h_new[k];
            poff += gru_hidden;
            for (int k = 0; k < d_model; k++)
                val += pq_W[d * peer_input_dim + poff + k] * fwd_ctx[k];
            poff += d_model;
            for (int k = 0; k < d_model; k++)
                val += pq_W[d * peer_input_dim + poff + k] * bwd_ctx[k];
            poff += d_model;
            val += pq_W[d * peer_input_dim + poff] * g;
            val += pq_W[d * peer_input_dim + poff + 1] * s;
            query[d] = val;
        }

        // Product-key argmax
        const float* keys_A = prod_keys_A + head * pk_dim * half_d;
        const float* keys_B = prod_keys_B + head * pk_dim * half_d;
        int best_a = 0; float best_sa = -1e30f;
        for (int k = 0; k < pk_dim; k++) {
            float dot = 0.0f;
            for (int d = 0; d < half_d; d++)
                dot += query[d] * LDG(&keys_A[k * half_d + d]);
            if (dot > best_sa) { best_sa = dot; best_a = k; }
        }
        int best_b = 0; float best_sb = -1e30f;
        for (int k = 0; k < pk_dim; k++) {
            float dot = 0.0f;
            for (int d = 0; d < half_d; d++)
                dot += query[half_d + d] * LDG(&keys_B[k * half_d + d]);
            if (dot > best_sb) { best_sb = dot; best_b = k; }
        }
        int expert_idx = best_a * pk_dim + best_b;
        if (expert_idx >= num_experts) expert_idx = num_experts - 1;
        if (expert_counts != nullptr)
            atomicAdd(&expert_counts[expert_idx], 1);

        // Expert MLP: ReLU hidden layer
        float head_out = s_expert_b2[expert_idx];
        for (int h = 0; h < expert_hidden; h++) {
            float z_val = s_expert_W1[expert_idx * expert_hidden + h] * g
                        + s_expert_b1[expert_idx * expert_hidden + h];
            z_val = fmaxf(z_val, 0.0f);
            head_out += s_expert_W2[expert_idx * expert_hidden + h] * z_val;
        }
        total_out += head_out;
    }

    // ── Step 4: Smart gradient ──
    float smart_grad = g + rescale * total_out / static_cast<float>(num_heads);

    // ── Step 5: Mu EMA update ──
    // Q state: mu is int8_t packed nibbles with block_size=32 scales
    const int mu_block = idx / 32;
    const int mu_byte  = idx / 2;
    const int mu_nib   = idx % 2;
    float mu_scale = mu_scales[mu_block];
    uint8_t mu_packed = static_cast<uint8_t>(mu_q[mu_byte]);
    int mu_raw = mu_nib ? ((mu_packed >> 4) & 0x0F) : (mu_packed & 0x0F);
    float mu_val = static_cast<float>(mu_raw - 8) * mu_scale;
    mu_val = alpha * mu_val + (1.0f - alpha) * g;
    // Stochastic round mu back to INT4
    unsigned mu_rng = hash_prng(idx + global_step * 6271u);
    int mu_q_new = float_to_int8_stochastic(mu_val / fmaxf(mu_scale, 1e-12f), mu_rng);
    mu_q_new = max(-8, min(7, mu_q_new));
    uint8_t mu_byte_old = static_cast<uint8_t>(mu_q[mu_byte]);
    if (mu_nib)
        mu_q[mu_byte] = static_cast<int8_t>((mu_byte_old & 0x0F) | (((mu_q_new + 8) & 0x0F) << 4));
    else
        mu_q[mu_byte] = static_cast<int8_t>((mu_byte_old & 0xF0) | ((mu_q_new + 8) & 0x0F));

    // ── Step 6: Adam update ──
    float fg = smart_grad + lamb_eff * mu_val;
    // Q state: exp_avg/exp_avg_sq are int8 block_size=8
    const int ea_block = idx / 8;
    float ea_scale = exp_avg_scales[ea_block];
    float easq_scale = exp_avg_sq_scales[ea_block];
    float ea = static_cast<float>(exp_avg_q[idx]) * ea_scale;
    float easq = static_cast<float>(exp_avg_sq_q[idx]) * easq_scale;
    ea = beta1 * ea + (1.0f - beta1) * fg;
    easq = beta2 * easq + (1.0f - beta2) * fg * fg;
    unsigned ea_rng = hash_prng(idx * 2u + global_step * 3571u);
    unsigned easq_rng = hash_prng(idx * 2u + 1u + global_step * 3571u);
    exp_avg_q[idx] = static_cast<int8_t>(float_to_int8_stochastic(ea / fmaxf(ea_scale, 1e-12f), ea_rng));
    exp_avg_sq_q[idx] = static_cast<int8_t>(float_to_int8_stochastic(easq / fmaxf(easq_scale, 1e-12f), easq_rng));

    float step_size = lr / bc1;
    float denom = sqrtf(easq / bc2) + eps;
    float p_val = static_cast<float>(param[idx]);
    p_val = p_val * (1.0f - lr * wd_eff) - step_size * ea / denom;
    param[idx] = static_cast<scalar_t>(p_val);
}

void launch_sg2_fused_elem_Q_fp32_generic_M_d16(
    torch::Tensor param,
    torch::Tensor grad,
    torch::Tensor sharpness,
    torch::Tensor exp_avg_q,
    torch::Tensor exp_avg_scales,
    torch::Tensor exp_avg_sq_q,
    torch::Tensor exp_avg_sq_scales,
    torch::Tensor mu_q,
    torch::Tensor mu_scales,
    torch::Tensor gru_state,
    torch::Tensor fwd_scan_out,
    torch::Tensor bwd_scan_out,
    float rescale, float alpha, float lamb_eff,
    float beta1, float beta2, float lr,
    float wd_eff, float eps, float bc1, float bc2,
    unsigned global_step,
    torch::Tensor active_mask,
    int d_model, int d_inner,
    int gru_hidden, int num_heads, int pk_dim,
    int expert_hidden, int num_experts
) {
    const int N = grad.numel();
    if (N == 0) return;
    const int grid = (N + 256 - 1) / 256;
    const int op_size = d_model * 16;
    const int gru_input_dim = 2 + 2 * d_model;
    const int gru_row_len = gru_input_dim + gru_hidden;
    const int gru_mat_size = gru_hidden * gru_row_len;
    const size_t smem_bytes = (2*op_size + 3*gru_mat_size + 3*gru_hidden
        + 3*num_experts*expert_hidden + num_experts) * sizeof(float);
    // Launch kernel (dispatch omitted — caller instantiates template)
    (void)grid; (void)smem_bytes;
}

// ===========================================================
//  sg2_fused_elem_Q_fp32_sm80_D_kernel  [Q/fp32/sm80/D]
// ===========================================================

template <typename scalar_t>
__launch_bounds__(256, 2)
__global__ void sg2_fused_elem_Q_fp32_sm80_D_kernel(
    scalar_t* __restrict__ param,
    const scalar_t* __restrict__ grad,
    const scalar_t* __restrict__ sharpness,
    int8_t* __restrict__ exp_avg_q,
    float* __restrict__ exp_avg_scales,
    int8_t* __restrict__ exp_avg_sq_q,
    float* __restrict__ exp_avg_sq_scales,
    int8_t* __restrict__ mu_q,
    float* __restrict__ mu_scales,
    __nv_bfloat16* __restrict__ gru_state,
    const float* __restrict__ fwd_scan_out,
    const float* __restrict__ bwd_scan_out,
    const float* __restrict__ out_proj_fwd_W,
    const float* __restrict__ out_proj_bwd_W,
    const float* __restrict__ gru_Wz, const float* __restrict__ gru_bz,
    const float* __restrict__ gru_Wr, const float* __restrict__ gru_br,
    const float* __restrict__ gru_Wh, const float* __restrict__ gru_bh,
    const float* __restrict__ peer_query_Ws,
    const float* __restrict__ prod_keys_A,
    const float* __restrict__ prod_keys_B,
    const float* __restrict__ expert_W1,
    const float* __restrict__ expert_b1,
    const float* __restrict__ expert_W2,
    const float* __restrict__ expert_b2,
    const float rescale, const float alpha, const float lamb_eff,
    const float beta1, const float beta2, const float lr,
    const float wd_eff, const float eps, const float bc1, const float bc2,
    const unsigned global_step,
    int* __restrict__ expert_counts,
    const int N, const int d_model, const int d_inner,
    const int gru_hidden, const int num_heads, const int pk_dim,
    const int expert_hidden, const int num_experts
) {
    const int gru_input_dim = 2 + 2 * d_model;
    const int gru_row_len = gru_input_dim + gru_hidden;
    const int op_size = d_model * d_inner;
    const int gru_mat_size = gru_hidden * gru_row_len;

    extern __shared__ float smem[];

    float* s_out_fwd = smem;
    float* s_out_bwd = smem + op_size;
    float* s_gru_Wz  = s_out_bwd + op_size;
    float* s_gru_Wr  = s_gru_Wz + gru_mat_size;
    float* s_gru_Wh  = s_gru_Wr + gru_mat_size;
    float* s_gru_bz  = s_gru_Wh + gru_mat_size;
    float* s_gru_br  = s_gru_bz + gru_hidden;
    float* s_gru_bh  = s_gru_br + gru_hidden;
    float* s_expert_W1 = s_gru_bh + gru_hidden;
    float* s_expert_b1 = s_expert_W1 + num_experts * expert_hidden;
    float* s_expert_W2 = s_expert_b1 + num_experts * expert_hidden;
    float* s_expert_b2 = s_expert_W2 + num_experts * expert_hidden;

    const int tid = threadIdx.x;
    const int block_size = blockDim.x;

    // cp.async prefetch out_proj weights
    for (int i = tid; i < 2 * op_size; i += block_size) {
        const float* src = (i < op_size) ? &out_proj_fwd_W[i] : &out_proj_bwd_W[i - op_size];
    #if GROK_CUDA && defined(__CUDA_ARCH__) && __CUDA_ARCH__ >= 800
        __pipeline_memcpy_async(&smem[i], src, sizeof(float));
    #else
        smem[i] = *src;
    #endif
    }
    // cp.async prefetch GRU weights
    const float* gru_gmem[] = {gru_Wz, gru_Wr, gru_Wh, gru_bz, gru_br, gru_bh};
    int gru_sizes[] = {gru_mat_size, gru_mat_size, gru_mat_size, gru_hidden, gru_hidden, gru_hidden};
    float* gru_dst = s_gru_Wz;
    int gru_offset = 0;
    for (int seg = 0; seg < 6; seg++) {
        for (int i = tid; i < gru_sizes[seg]; i += block_size) {
    #if GROK_CUDA && defined(__CUDA_ARCH__) && __CUDA_ARCH__ >= 800
            __pipeline_memcpy_async(&gru_dst[gru_offset + i], &gru_gmem[seg][i], sizeof(float));
    #else
            gru_dst[gru_offset + i] = gru_gmem[seg][i];
    #endif
        }
        gru_offset += gru_sizes[seg];
    }
    #if GROK_CUDA && defined(__CUDA_ARCH__) && __CUDA_ARCH__ >= 800
    __pipeline_commit();
    #endif

    for (int i = tid; i < num_experts * expert_hidden; i += block_size) {
    #if GROK_CUDA && defined(__CUDA_ARCH__) && __CUDA_ARCH__ >= 800
        __pipeline_memcpy_async(&s_expert_W1[i], &expert_W1[i], sizeof(float));
        __pipeline_memcpy_async(&s_expert_b1[i], &expert_b1[i], sizeof(float));
        __pipeline_memcpy_async(&s_expert_W2[i], &expert_W2[i], sizeof(float));
    #else
        s_expert_W1[i] = expert_W1[i];
        s_expert_b1[i] = expert_b1[i];
        s_expert_W2[i] = expert_W2[i];
    #endif
    }
    for (int i = tid; i < num_experts; i += block_size) {
    #if GROK_CUDA && defined(__CUDA_ARCH__) && __CUDA_ARCH__ >= 800
        __pipeline_memcpy_async(&s_expert_b2[i], &expert_b2[i], sizeof(float));
    #else
        s_expert_b2[i] = expert_b2[i];
    #endif
    }
    #if GROK_CUDA && defined(__CUDA_ARCH__) && __CUDA_ARCH__ >= 800
    __pipeline_commit();
    __pipeline_wait_prior(0);
    #endif
    __syncthreads();

    // Per-element processing
    const int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx >= N) return;

    float g = static_cast<float>(grad[idx]);
    float s = static_cast<float>(sharpness[idx]);
    if (!isfinite(g)) g = 0.0f;
    if (!isfinite(s)) s = 0.0f;
    const int half_d = d_model / 2;
    const int peer_input_dim = gru_hidden + 2 * d_model + 2;

    // ── Step 1: Mamba out_proj ──
    float fwd_scan[MAX_D_INNER], bwd_scan[MAX_D_INNER];
    for (int j = 0; j < d_inner; j += 4) {
        float4 fwd4 = *reinterpret_cast<const float4*>(&fwd_scan_out[idx * d_inner + j]);
        float4 bwd4 = *reinterpret_cast<const float4*>(&bwd_scan_out[idx * d_inner + j]);
        fwd_scan[j]   = fwd4.x; fwd_scan[j+1] = fwd4.y;
        fwd_scan[j+2] = fwd4.z; fwd_scan[j+3] = fwd4.w;
        bwd_scan[j]   = bwd4.x; bwd_scan[j+1] = bwd4.y;
        bwd_scan[j+2] = bwd4.z; bwd_scan[j+3] = bwd4.w;
    }

    float fwd_ctx[MAX_D_MODEL], bwd_ctx[MAX_D_MODEL];
    for (int d = 0; d < d_model; d++) {
        float fwd_val = 0.0f, bwd_val = 0.0f;
        for (int j = 0; j < d_inner; j++) {
            fwd_val += s_out_fwd[d * d_inner + j] * fwd_scan[j];
            bwd_val += s_out_bwd[d * d_inner + j] * bwd_scan[j];
        }
        fwd_ctx[d] = fwd_val;
        bwd_ctx[d] = bwd_val;
    }

    // ── Step 2: GRU update ──
    float h_old[MAX_GRU_HIDDEN];
    for (int j = 0; j < gru_hidden; j++)
        h_old[j] = static_cast<float>(gru_state[idx * gru_hidden + j]);

    float z_gate[MAX_GRU_HIDDEN], r_gate[MAX_GRU_HIDDEN];
    for (int j = 0; j < gru_hidden; j++) {
        float val_z = s_gru_bz[j];
        float val_r = s_gru_br[j];
        val_z += s_gru_Wz[j * gru_row_len + 0] * g;
        val_z += s_gru_Wz[j * gru_row_len + 1] * s;
        val_r += s_gru_Wr[j * gru_row_len + 0] * g;
        val_r += s_gru_Wr[j * gru_row_len + 1] * s;
        int off = 2;
        for (int d = 0; d < d_model; d++) {
            val_z += s_gru_Wz[j * gru_row_len + off + d] * fwd_ctx[d];
            val_r += s_gru_Wr[j * gru_row_len + off + d] * fwd_ctx[d];
        }
        off += d_model;
        for (int d = 0; d < d_model; d++) {
            val_z += s_gru_Wz[j * gru_row_len + off + d] * bwd_ctx[d];
            val_r += s_gru_Wr[j * gru_row_len + off + d] * bwd_ctx[d];
        }
        off += d_model;
        for (int k = 0; k < gru_hidden; k++) {
            val_z += s_gru_Wz[j * gru_row_len + off + k] * h_old[k];
            val_r += s_gru_Wr[j * gru_row_len + off + k] * h_old[k];
        }
        z_gate[j] = 1.0f / (1.0f + expf(-val_z));
        r_gate[j] = 1.0f / (1.0f + expf(-val_r));
    }

    float h_new[MAX_GRU_HIDDEN];
    for (int j = 0; j < gru_hidden; j++) {
        float val = s_gru_bh[j];
        val += s_gru_Wh[j * gru_row_len + 0] * g;
        val += s_gru_Wh[j * gru_row_len + 1] * s;
        int off = 2;
        for (int d = 0; d < d_model; d++)
            val += s_gru_Wh[j * gru_row_len + off + d] * fwd_ctx[d];
        off += d_model;
        for (int d = 0; d < d_model; d++)
            val += s_gru_Wh[j * gru_row_len + off + d] * bwd_ctx[d];
        off += d_model;
        for (int k = 0; k < gru_hidden; k++)
            val += s_gru_Wh[j * gru_row_len + off + k] * (r_gate[k] * h_old[k]);
        float h_tilde = tanhf(val);
        h_new[j] = (1.0f - z_gate[j]) * h_old[j] + z_gate[j] * h_tilde;
    }

    unsigned gru_rng = hash_prng(idx * gru_hidden + global_step * 7919u);
    for (int j = 0; j < gru_hidden; j++) {
        gru_state[idx * gru_hidden + j] = float_to_bf16_stochastic(h_new[j], gru_rng);
        gru_rng = hash_prng(gru_rng + j);
    }

    // ── Step 3: Multi-head PEER routing + expert MLP ──
    float total_out = 0.0f;
    for (int head = 0; head < num_heads; head++) {
        const float* pq_W = peer_query_Ws + head * d_model * peer_input_dim;
        float query[MAX_D_MODEL];
        for (int d = 0; d < d_model; d++) {
            float val = 0.0f;
            int poff = 0;
            for (int k = 0; k < gru_hidden; k++)
                val += pq_W[d * peer_input_dim + poff + k] * h_new[k];
            poff += gru_hidden;
            for (int k = 0; k < d_model; k++)
                val += pq_W[d * peer_input_dim + poff + k] * fwd_ctx[k];
            poff += d_model;
            for (int k = 0; k < d_model; k++)
                val += pq_W[d * peer_input_dim + poff + k] * bwd_ctx[k];
            poff += d_model;
            val += pq_W[d * peer_input_dim + poff] * g;
            val += pq_W[d * peer_input_dim + poff + 1] * s;
            query[d] = val;
        }

        // Product-key argmax
        const float* keys_A = prod_keys_A + head * pk_dim * half_d;
        const float* keys_B = prod_keys_B + head * pk_dim * half_d;
        int best_a = 0; float best_sa = -1e30f;
        for (int k = 0; k < pk_dim; k++) {
            float dot = 0.0f;
            for (int d = 0; d < half_d; d++)
                dot += query[d] * LDG(&keys_A[k * half_d + d]);
            if (dot > best_sa) { best_sa = dot; best_a = k; }
        }
        int best_b = 0; float best_sb = -1e30f;
        for (int k = 0; k < pk_dim; k++) {
            float dot = 0.0f;
            for (int d = 0; d < half_d; d++)
                dot += query[half_d + d] * LDG(&keys_B[k * half_d + d]);
            if (dot > best_sb) { best_sb = dot; best_b = k; }
        }
        int expert_idx = best_a * pk_dim + best_b;
        if (expert_idx >= num_experts) expert_idx = num_experts - 1;
        if (expert_counts != nullptr)
            atomicAdd(&expert_counts[expert_idx], 1);

        // Expert MLP: ReLU hidden layer
        float head_out = s_expert_b2[expert_idx];
        for (int h = 0; h < expert_hidden; h++) {
            float z_val = s_expert_W1[expert_idx * expert_hidden + h] * g
                        + s_expert_b1[expert_idx * expert_hidden + h];
            z_val = fmaxf(z_val, 0.0f);
            head_out += s_expert_W2[expert_idx * expert_hidden + h] * z_val;
        }
        total_out += head_out;
    }

    // ── Step 4: Smart gradient ──
    float smart_grad = g + rescale * total_out / static_cast<float>(num_heads);

    // ── Step 5: Mu EMA update ──
    // Q state: mu is int8_t packed nibbles with block_size=32 scales
    const int mu_block = idx / 32;
    const int mu_byte  = idx / 2;
    const int mu_nib   = idx % 2;
    float mu_scale = mu_scales[mu_block];
    uint8_t mu_packed = static_cast<uint8_t>(mu_q[mu_byte]);
    int mu_raw = mu_nib ? ((mu_packed >> 4) & 0x0F) : (mu_packed & 0x0F);
    float mu_val = static_cast<float>(mu_raw - 8) * mu_scale;
    mu_val = alpha * mu_val + (1.0f - alpha) * g;
    // Stochastic round mu back to INT4
    unsigned mu_rng = hash_prng(idx + global_step * 6271u);
    int mu_q_new = float_to_int8_stochastic(mu_val / fmaxf(mu_scale, 1e-12f), mu_rng);
    mu_q_new = max(-8, min(7, mu_q_new));
    uint8_t mu_byte_old = static_cast<uint8_t>(mu_q[mu_byte]);
    if (mu_nib)
        mu_q[mu_byte] = static_cast<int8_t>((mu_byte_old & 0x0F) | (((mu_q_new + 8) & 0x0F) << 4));
    else
        mu_q[mu_byte] = static_cast<int8_t>((mu_byte_old & 0xF0) | ((mu_q_new + 8) & 0x0F));

    // ── Step 6: Adam update ──
    float fg = smart_grad + lamb_eff * mu_val;
    // Q state: exp_avg/exp_avg_sq are int8 block_size=8
    const int ea_block = idx / 8;
    float ea_scale = exp_avg_scales[ea_block];
    float easq_scale = exp_avg_sq_scales[ea_block];
    float ea = static_cast<float>(exp_avg_q[idx]) * ea_scale;
    float easq = static_cast<float>(exp_avg_sq_q[idx]) * easq_scale;
    ea = beta1 * ea + (1.0f - beta1) * fg;
    easq = beta2 * easq + (1.0f - beta2) * fg * fg;
    unsigned ea_rng = hash_prng(idx * 2u + global_step * 3571u);
    unsigned easq_rng = hash_prng(idx * 2u + 1u + global_step * 3571u);
    exp_avg_q[idx] = static_cast<int8_t>(float_to_int8_stochastic(ea / fmaxf(ea_scale, 1e-12f), ea_rng));
    exp_avg_sq_q[idx] = static_cast<int8_t>(float_to_int8_stochastic(easq / fmaxf(easq_scale, 1e-12f), easq_rng));

    float step_size = lr / bc1;
    float denom = sqrtf(easq / bc2) + eps;
    float p_val = static_cast<float>(param[idx]);
    p_val = p_val * (1.0f - lr * wd_eff) - step_size * ea / denom;
    param[idx] = static_cast<scalar_t>(p_val);
}

void launch_sg2_fused_elem_Q_fp32_sm80_D(
    torch::Tensor param,
    torch::Tensor grad,
    torch::Tensor sharpness,
    torch::Tensor exp_avg_q,
